import React, { useState, useCallback, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  StatusBadge,
  dispatchAppToast,
  LinPageLayout,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { gtService } from '../../../services/gt/gtService';
import type { CostSheetDto, WipBalanceDto } from '../../../services/gt/models';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';
import { giaThanhPageLabels as L } from '../../../constants/giaThanhPageLabels';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { useVoucherListTableBusy } from '../../../components/list/useVoucherListTableBusy';
import {
  DEFAULT_VOUCHER_LIST_PAGE_SIZE,
  VoucherListPagination,
  type VoucherListPageSize,
} from '../../../components/list/VoucherListPagination';

const TEST_ID = 'erp-gia-thanh';
const PAGE_ID = 'gt-gia-thanh';
const PAGE_SIZE = DEFAULT_VOUCHER_LIST_PAGE_SIZE;

const STATUS_OPTIONS = [
  { value: '', label: L.list.statusAll },
  { value: 'Draft', label: L.list.statusDraft },
  { value: 'Calculated', label: L.list.statusCalculated },
  { value: 'Approved', label: L.list.statusApproved },
  { value: 'Posted', label: L.list.statusPosted },
];

const GiaThanhListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState<VoucherListPageSize>(PAGE_SIZE);
  const [status, setStatus] = useState('');
  const [items, setItems] = useState<CostSheetDto[]>([]);
  const [wipRows, setWipRows] = useState<WipBalanceDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);

  const { showTableLoading } = useVoucherListTableBusy(loading);

  const handleLoad = useCallback(() => {
    setLoading(true);
    Promise.all([
      gtService.getCostSheets({
        month: Number(month),
        year: Number(year),
        status: status || undefined,
        page,
        pageSize,
      }),
      gtService.getWipBalance(Number(month), Number(year)),
    ])
      .then(([res, wip]) => {
        setItems(res.items);
        setTotalCount(res.totalCount);
        setWipRows(wip);
      })
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, L.list.loadError),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [month, year, status, page, pageSize, dispatch]);

  const refresh = useCallback(() => {
    handleLoad();
  }, [handleLoad]);

  const wipOpening = wipRows.reduce((sum, row) => sum + row.openingAmount, 0);
  const wipClosing = wipRows.reduce((sum, row) => sum + row.closingAmount, 0);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!cancelled) handleLoad();
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [handleLoad]);

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canChart: false,
      canPrint: false,
    }),
    [refresh],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-month`,
        content: (
          <Select
            label={L.list.filterMonth}
            value={month}
            onChange={e => {
              setMonth(e.target.value);
              setPage(1);
            }}
            options={MONTH_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-month`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-year`,
        content: (
          <Select
            label={L.list.filterYear}
            value={year}
            onChange={e => {
              setYear(e.target.value);
              setPage(1);
            }}
            options={yearOptions()}
            fullWidth
            data-testid={`${TEST_ID}-year`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label={L.list.filterStatus}
            value={status}
            onChange={e => {
              setStatus(e.target.value);
              setPage(1);
            }}
            options={STATUS_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-status`}
          />
        ),
      },
    ],
    [month, year, status],
  );

  const wipSummary = (
    <div className={erp.summaryBar} data-testid={`${TEST_ID}-wip-summary`}>
      <div className={erp.summaryItem}>
        <label className={erp.label}>{L.list.wipOpening}</label>
        <strong>{formatVnd(wipOpening)}</strong>
      </div>
      <div className={erp.summaryItem}>
        <label className={erp.label}>{L.list.wipClosing}</label>
        <strong>{formatVnd(wipClosing)}</strong>
      </div>
      <div className={erp.summaryItem}>
        <label className={erp.label}>{L.list.wipOrderCount}</label>
        <strong>{wipRows.length}</strong>
      </div>
    </div>
  );

  const listBody =
    !showTableLoading && items.length === 0 ? (
      <>
        {wipSummary}
        <div className={erp.empty}>{L.list.empty}</div>
      </>
    ) : !showTableLoading ? (
      <>
        {wipSummary}
        <div className={erp.tableWrapper}>
          <table className={erp.table}>
            <thead>
              <tr>
                <th>{L.list.colCode}</th>
                <th>{L.list.colProduct}</th>
                <th className={erp.colRight}>{L.detail.actualQty}</th>
                <th className={erp.colRight}>{L.list.colTotal}</th>
                <th className={erp.colRight}>{L.list.colUnitCost}</th>
                <th>{L.list.colStatus}</th>
              </tr>
            </thead>
            <tbody>
              {items.map(r => (
                <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
                  <td>
                    <button
                      type="button"
                      className={erp.codeLink}
                      onClick={() => navigate(`/gt/gia-thanh/${r.id}`)}
                    >
                      <code>{r.code}</code>
                    </button>
                  </td>
                  <td>{r.productName ?? r.productCode}</td>
                  <td className={erp.colRight}>{r.actualQty}</td>
                  <td className={erp.colRight}>{formatVnd(r.totalCost)}</td>
                  <td className={erp.colRight}>{formatVnd(r.unitCost)}</td>
                  <td>
                    <StatusBadge status={r.status} />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: L.list.title,
          titleIconClass: 'fas fa-industry',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={L.list.listTitle}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={Math.min(pageSize, 8)}
        footer={
          totalCount > 0 ? (
            <VoucherListPagination
              testIdPrefix={TEST_ID}
              page={page}
              totalCount={totalCount}
              pageSize={pageSize}
              onPageChange={setPage}
              onPageSizeChange={size => {
                setPageSize(size as VoucherListPageSize);
                setPage(1);
              }}
            />
          ) : undefined
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default GiaThanhListPage;
